+import { ConfigParseError } from "./errors.ts";
+
+/** Parse the simple key=value RC format. */
+export function parseRc(content: string, path: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  try {
+    for (const rawLine of content.split(/\\r?\
/)) {
+      const line = rawLine.trim();
+      if (!line || line.startsWith("#")) continue;
+      const index = line.indexOf("=");
+      if (index === -1) throw new Error(`Invalid line "${rawLine}"`);
+      const key = line.slice(0, index).trim();
+      let value = line.slice(index + 1).trim();
+      if (!key) throw new Error(`Invalid line "${rawLine}"`);
+      if (value.startsWith('"')) {
+        if (!value.endsWith('"') || value.length === 1) {
+          throw new Error(`Unterminated quoted value for "${key}"`);
+        }
+        value = value.slice(1, -1);
+      } else if (value === "true") {
+        result[key] = true;
+        continue;
+      } else if (value === "false") {
+        result[key] = false;
+        continue;
+      } else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:[eE][-+]?\\d+)?$/.test(value)) {
+        result[key] = Number(value);
+        continue;
+      }
+      result[key] = value;
+    }
+    return result;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+export function parseJson(content: string, path: string): Record<string, unknown> {
+  try {
+    const result: unknown = JSON.parse(content);
+    if (!result || Array.isArray(result) || typeof result !== "object") {
+      throw new Error("The root value must be an object.");
+    }
+    return result as Record<string, unknown>;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+/** Flatten nested object keys using dot notation and camel-case kebab keys. */
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+  result: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = rawKey.replace(/-([a-zA-Z])/g, (_, char: string) => char.toUpperCase());
+    const name = prefix ? `${prefix}.${key}` : key;
+    if (item && !Array.isArray(item) && typeof item === "object") {
+      flattenConfig(item as Record<string, unknown>, name, result);
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
